      "content": "\"\"\"Spoolman per-filament usage tracking for active prints.\n\nCaptures AMS tray state and G-code data at print start, then reports\nper-filament usage to the correct Spoolman spools at print completion.\nSupports accurate partial usage reporting for failed/cancelled prints.\n\"\"\"\n\nimport json\nimport logging\n\nfrom sqlalchemy import delete, select\n\nfrom backend.app.core.config import settings as app_settings\nfrom backend.app.core.database import async_session\nfrom backend.app.services.spoolman import get_spoolman_client, init_spoolman_client\n\nlogger = logging.getLogger(__name__)\n\n# Zero UUID used by Bambu printers for empty/unset tray_uuid\n_ZERO_UUID = \"00000000000000000000000000000000\"\n\n\ndef _resolve_spool_tag(tray_info: dict) -> str:\n    \"\"\"Get the best spool identifier from tray info (prefer tray_uuid, fallback to filament_id).\"\"\"\n    tray_uuid = tray_info.get(\"tray_uuid\")\n    if tray_uuid and tray_uuid != _ZERO_UUID:\n        return tray_uuid\n    filament_id = tray_info.get(\"filament_id\")\n    if filament_id:\n        return filament_id\n    return \"\"\n\n\ndef _parse_gcode_line(line: str):\n    \"\"\"Parse a single G-code line for filament usage commands.\n\n    Returns a tuple (command, value) or (None, None) if not relevant.\n    \"\"\"\n    line = line.strip()\n    if line.startswith(\"M117\"):  # Example: M117 Filament used: 1234\n        parts = line.split()\n        for part in parts:\n            if part.isdigit():\n                return (\"M117\", int(part))\n    elif line.startswith(\"G1\"):  # Example: G1 E123.45\n        parts = line.split()\n        for part in parts:\n            if part.startswith(\"E\"):\n                try:\n                    value = float(part[1:])\n                    return (\"G1\", value)\n                except ValueError:\n                    pass\n    return (None, None)\n\n\ndef calculate_filament_usage(gcode_lines):\n    \"\"\"Calculate filament usage from G-code lines.\n\n    Returns the total filament used as a float.\n    \"\"\"\n    last_e_value = 0.0\n    total_used = 0.0\n    for line in gcode_lines:\n        cmd, val = _parse_gcode_line(line)\n        if cmd == \"G1\" and val is not None:\n            if val > last_e_value:\n                total_used += val - last_e_value\n            last_e_value = val\n    return total_used\n\n\ndef report_usage_to_spoolman(spoolman_client, spool_tag, usage):\n    \"\"\"Report filament usage to Spoolman client.\"\"\"\n    if not spool_tag or usage <= 0:\n        logger.debug(f\"Skipping report: spool_tag={spool_tag}, usage={usage}\")\n        return\n    try:\n        spoolman_client.report_usage(spool_tag, usage)\n        logger.info(f\"Reported usage {usage} to spool {spool_tag}\")\n    except Exception as e:\n        logger.error(f\"Failed"}], "localized": true}
